// Pseudo risk score function
function calculateRiskScore(query, policyRules) {
  let riskScore = 0;

  for (const rule of policyRules) {
    if (query.includes(rule.trigger)) {
      riskScore += rule.severity;
    }
  }

  return Math.min(riskScore, 100);
}

// Determine if escalation is needed
function requiresEscalation(score, threshold = 75) {
  return score > threshold;
}
