    method: 'POST',
    headers: { 'Ocp-Apim-Subscription-Key': apiKey, 'Content-Type': 'application/json' },
    body: JSON.stringify({ documents: [{ id: '1', language: 'en', text }] })
  });
  const { documents } = await response.json();
  let redacted = text;
  documents[0].entities.forEach(entity => {
    if (entity.category.includes('Person') || entity.category.includes('Email') || entity.category.includes('Phone')) {
      redacted = redacted.replace(entity.text, '[REDACTED]');
    }
  });
  return redacted;
}
