// Compute disparate impact ratio for a batch of model outputs
function computeDisparateImpact(outcomes, sensitiveAttribute) {
  const favorable = outcomes.filter(o => o.prediction === 1);
  const unfavorable = outcomes.filter(o => o.prediction === 0);

  const groupA = outcomes.filter(o => o[sensitiveAttribute] === 'A');
  const groupB = outcomes.filter(o => o[sensitiveAttribute] === 'B');

  const rateA = groupA.filter(o => o.prediction === 1).length / groupA.length;
  const rateB = groupB.filter(o => o.prediction === 1).length / groupB.length;

  // Disparate impact: ratio should be > 0.8 for fairness
  return Math.min(rateA, rateB) / Math.max(rateA, rateB);
}

